19	export function addNode(title: string, body: string, tags: string[]): Node {
20	  const graph = load();
21	  const node: Node = {
22	    id: randomUUID(),
23	    title,
24	    body,
25	    tags,
26	    createdAt: new Date().toISOString(),
27	    updatedAt: new Date().toISOString(),
28	  };
29	  graph.nodes.push(node);
30	  save(graph);
31	  return node;
32	}
33	
34	export function link(fromTitle: string, toTitle: string, label?: string): Edge {
35	  const graph = load();
36	  const from = graph.nodes.find((n) => n.title === fromTitle);
37	  const to = graph.nodes.find((n) => n.title === toTitle);
38	  if (!from || !to) throw new Error(`Node not found`);
39	  const edge: Edge = { from: from.id, to: to.id, label, weight: 1 };
40	  graph.edges.push(edge);
41	  save(graph);
42	  return edge;
43	}
44	
45	export function removeNode(title: string): { node: Node; edgeCount: number } | null {
46	  const graph = load();
47	  const node = graph.nodes.find((n) => n.title === title);
48	  if (!node) return null;
49	  graph.nodes = graph.nodes.filter((n) => n.id !== node.id);
50	  const removedEdges = graph.edges.filter((e) => e.from === node.id || e.to === node.id);
51	  graph.edges = graph.edges.filter((e) => e.from !== node.id && e.to !== node.id);
52	  save(graph);
53	  return { node, edgeCount: removedEdges.length };
54	}
