56	export function exportMarkdown(): string {
57	  const graph = load();
58	  const lines: string[] = ["# Knowledge Map\n"];
59	  for (const node of graph.nodes) {
60	    lines.push(`## ${node.title}`);
61	    if (node.tags.length) lines.push(`*tags: ${node.tags.join(", ")}*\n`);
62	    lines.push(node.body);
63	    const outgoing = graph.edges.filter((e) => e.from === node.id);
64	    if (outgoing.length) {
65	      lines.push("\n**Links:**");
66	      for (const edge of outgoing) {
67	        const target = graph.nodes.find((n) => n.id === edge.to);
68	        if (target) lines.push(`- → [${target.title}]${edge.label ? ` *(${edge.label})*` : ""}`);
69	      }
70	    }
71	    lines.push("");
72	  }
73	  return lines.join("\n");
74	}
