85	export function mostConnectedNode(graph: Graph): { node: Node | null; degree: number } {
86	  if (graph.edges.length === 0) {
87	    return { node: null, degree: 0 };
88	  }
89	
90	  const degreeMap = new Map<string, number>();
91	
92	  for (const edge of graph.edges) {
93	    // Bidirectional degree: each edge contributes +1 to both nodes
94	    // regardless of direction, counting both as connected
95	    degreeMap.set(edge.from, (degreeMap.get(edge.from) ?? 0) + 1);
96	    degreeMap.set(edge.to, (degreeMap.get(edge.to) ?? 0) + 1);
97	  }
98	
99	  let maxDegree = -1;
100	  let maxNode: Node | null = null;
101	
102	  for (const node of graph.nodes) {
103	    const degree = degreeMap.get(node.id) ?? 0;
104	    if (degree > maxDegree) {
105	      maxDegree = degree;
106	      maxNode = node;
107	    }
108	  }
109	
110	  return { node: maxNode, degree: maxDegree };
111	}
